+// ---------------------------------------------------------------------------
+// Email Validation
+// ---------------------------------------------------------------------------
+
+/**
+ * Validates an email address format.
+ *
+ * Uses a reasonable regex that covers the vast majority of valid email
+ * addresses without being overly permissive. Checks:
+ * - Has exactly one @ symbol
+ * - Local part is non-empty and uses allowed characters
+ * - Domain has at least one dot and valid characters
+ * - Domain TLD is at least 2 characters
+ *
+ * @param email - The email address to validate.
+ * @returns true if the email format is valid.
+ */
+export function isValidEmail(email: string): boolean {
+  if (!email || typeof email !== 'string') {
+    return false;
+  }
+  const trimmed = email.trim();
+  if (trimmed.length === 0 || trimmed.length > 254) {
+    return false;
+  }
+  // Standard email validation regex
+  const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*\.[a-zA-Z]{2,}$/;
+  return emailRegex.test(trimmed);
+}
+
+/**
+ * Resolves a recipient identifier to a normalised string.
+ *
+ * Trims whitespace and normalises to lowercase. If the recipient looks
+ * like a valid email address, it is returned as-is. If it doesn't look
+ * like an email (e.g., a user ID like "user-1"), it is still returned
+ * but marked as unvalidated — the caller can decide how to handle it.
+ *
+ * Returns null only if the input is empty or not a string.
+ *
+ * @param recipient - The recipient string from the notification payload.
+ * @returns An object with the normalised recipient and whether it's a valid email, or null if empty.
+ */
+export function resolveRecipient(recipient: string): {
+  address: string;
+  isValidEmail: boolean;
+} | null {
+  if (!recipient || typeof recipient !== 'string') {
+    return null;
+  }
+  const normalised = recipient.trim().toLowerCase();
+  if (normalised.length === 0) {
+    return null;
+  }
+  return {
+    address: normalised,
+    isValidEmail: isValidEmail(normalised),
+  };
+}
+
+// ---------------------------------------------------------------------------
+// Email Template Engine
+// ---------------------------------------------------------------------------
+
+/**
+ * Renders an email template for the given notification payload.
+ *
+ * Each notification type has a dedicated template that generates both
+ * HTML and plain-text versions of the email. The templates include
+ * proper formatting, branding, and contextual content based on the
+ * notification type and metadata.
+ *
+ * @param payload - The notification payload to render.
+ * @param companyName - The company name for branding.
+ * @returns A rendered email with HTML, text, and subject.
+ */
+export function renderEmailTemplate(
+  payload: NotificationPayload,
+  companyName: string,
+): RenderedEmail {
+  switch (payload.type) {
+    case 'order_confirmation':
+      return renderOrderConfirmation(payload, companyName);
+    case 'order_status_update':
+      return renderOrderStatusUpdate(payload, companyName);
+    case 'welcome':
+      return renderWelcome(payload, companyName);
+    case 'account_updated':
+      return renderAccountUpdated(payload, companyName);
+    default:
+      return renderGeneric(payload, companyName);
+  }
+}
+
+/**
+ * Wraps HTML content in a standard email layout with header and footer.
+ */
+function wrapHtmlLayout(
+  title: string,
+  bodyContent: string,
+  companyName: string,
+): string {
+  return `<!DOCTYPE html>
+<html>
+<head>
+  <meta charset="utf-8">
+  <title>${escapeHtml(title)}</title>
+</head>
+<body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333; max-width: 600px; margin: 0 auto; padding: 20px;">
+  <div style="border-bottom: 2px solid #007bff; padding-bottom: 10px; margin-bottom: 20px;">
+    <h2 style="color: #007bff; margin: 0;">${escapeHtml(companyName)}</h2>
+  </div>
+  ${bodyContent}
+  <div style="border-top: 1px solid #ddd; padding-top: 15px; margin-top: 30px; font-size: 12px; color: #888;">
+    <p>This is an automated message from ${escapeHtml(companyName)}. Please do not reply directly to this email.</p>
+  </div>
+</body>
+</html>`;
+}
+
+/**
+ * Escapes HTML special characters to prevent XSS in email templates.
+ */
+function escapeHtml(text: string): string {
+  return text
+    .replace(/&/g, '&amp;')
+    .replace(/</g, '&lt;')
+    .replace(/>/g, '&gt;')
+    .replace(/"/g, '&quot;')
+    .replace(/'/g, '&#039;');
+}
+
+function renderOrderConfirmation(
+  payload: NotificationPayload,
+  companyName: string,
+): RenderedEmail {
+  const bodyHtml = `
+  <h3 style="color: #28a745;">Order Confirmed!</h3>
+  <p>Thank you for your order.</p>
+  <div style="background: #f8f9fa; padding: 15px; border-radius: 5px; margin: 15px 0;">
+    <p style="margin: 0;">${escapeHtml(payload.body)}</p>
+  </div>
+  <p>We'll send you updates as your order progresses.</p>`;
+
+  return {
+    subject: payload.subject,
+    html: wrapHtmlLayout(payload.subject, bodyHtml, companyName),
+    text: `${companyName}\n\nOrder Confirmed!\n\nThank you for your order.\n\n${payload.body}\n\nWe'll send you updates as your order progresses.\n\nThis is an automated message from ${companyName}.`,
+  };
+}
+
+function renderOrderStatusUpdate(
+  payload: NotificationPayload,
+  companyName: string,
+): RenderedEmail {
+  const isHighPriority =
+    payload.priority === 'high' || payload.priority === 'urgent';
+  const statusColor = isHighPriority ? '#dc3545' : '#17a2b8';
+  const statusIcon = isHighPriority ? '⚠️' : 'ℹ️';
+
+  const bodyHtml = `
+  <h3 style="color: ${statusColor};">${statusIcon} Order Status Update</h3>
+  <div style="background: #f8f9fa; padding: 15px; border-radius: 5px; margin: 15px 0;">
+    <p style="margin: 0;">${escapeHtml(payload.body)}</p>
+  </div>
+  <p>If you have any questions, please contact our support team.</p>`;
+
+  return {
+    subject: payload.subject,
+    html: wrapHtmlLayout(payload.subject, bodyHtml, companyName),
+    text: `${companyName}\n\n${statusIcon} Order Status Update\n\n${payload.body}\n\nIf you have any questions, please contact our support team.\n\nThis is an automated message from ${companyName}.`,
+  };
+}
+
+function renderWelcome(
+  payload: NotificationPayload,
+  companyName: string,
+): RenderedEmail {
+  const bodyHtml = `
+  <h3 style="color: #007bff;">Welcome! 🎉</h3>
+  <p>${escapeHtml(payload.body)}</p>
+  <div style="background: #e7f3ff; padding: 15px; border-radius: 5px; margin: 15px 0;">
+    <h4 style="margin-top: 0;">Getting Started:</h4>
+    <ul>
+      <li>Browse our product catalog</li>
+      <li>Set up your profile preferences</li>
+      <li>Place your first order</li>
+    </ul>
+  </div>
+  <p>We're excited to have you on board!</p>`;
+
+  return {
+    subject: payload.subject,
+    html: wrapHtmlLayout(payload.subject, bodyHtml, companyName),
+    text: `${companyName}\n\nWelcome! 🎉\n\n${payload.body}\n\nGetting Started:\n- Browse our product catalog\n- Set up your profile preferences\n- Place your first order\n\nWe're excited to have you on board!\n\nThis is an automated message from ${companyName}.`,
+  };
+}
+
+function renderAccountUpdated(
+  payload: NotificationPayload,
+  companyName: string,
+): RenderedEmail {
+  const bodyHtml = `
+  <h3 style="color: #ffc107;">Account Updated</h3>
+  <p>${escapeHtml(payload.body)}</p>
+  <p style="color: #666;">If you did not make these changes, please contact our support team immediately.</p>`;
+
+  return {
+    subject: payload.subject,
+    html: wrapHtmlLayout(payload.subject, bodyHtml, companyName),
+    text: `${companyName}\n\nAccount Updated\n\n${payload.body}\n\nIf you did not make these changes, please contact our support team immediately.\n\nThis is an automated message from ${companyName}.`,
+  };
+}
+
+function renderGeneric(
+  payload: NotificationPayload,
+  companyName: string,
+): RenderedEmail {
+  const bodyHtml = `
+  <h3>${escapeHtml(payload.subject)}</h3>
+  <p>${escapeHtml(payload.body)}</p>`;
