import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
  isValidEmail,
  resolveRecipient,
  renderEmailTemplate,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  const samplePayload: NotificationPayload = {
    type: 'order_confirmation',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-0001',
    body: 'Your order has been placed.',
    channel: 'email',
    priority: 'normal',
  };

  beforeEach(() => {
    adapter = new EmailAdapter({ stubMode: true });
  });

  // -------------------------------------------------------------------------
  // send() — core delivery
  // -------------------------------------------------------------------------

  describe('send', () => {
    it('should succeed in stub mode', async () => {
      const result = await adapter.send(samplePayload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
    });

    it('should record sent emails in stub mode', async () => {
      await adapter.send(samplePayload);

      const sentEmails = adapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]?.to).toBe('alice@example.com');
      expect(sentEmails[0]?.subject).toBe('Order Confirmation: order-0001');
    });

    it('should fail in non-stub mode (no real SMTP configured)', async () => {
      const productionAdapter = new EmailAdapter({ stubMode: false });
      const result = await productionAdapter.send(samplePayload);

      expect(result.success).toBe(false);
      expect(result.failureReason).toBeDefined();
    });

    it('should fail for invalid recipient email', async () => {
      const badPayload: NotificationPayload = {
        ...samplePayload,
        recipient: 'not-an-email',
      };

      const result = await adapter.send(badPayload);

      expect(result.success).toBe(false);
      expect(result.failureReason).toContain('Invalid recipient email address');
    });

    it('should fail for empty recipient', async () => {
      const badPayload: NotificationPayload = {
        ...samplePayload,
        recipient: '',
      };

      const result = await adapter.send(badPayload);

      expect(result.success).toBe(false);
      expect(result.failureReason).toContain('Invalid recipient email address');
    });

    it('should normalise recipient email to lowercase', async () => {
      const upperPayload: NotificationPayload = {
        ...samplePayload,
        recipient: 'Alice@Example.COM',
      };

      await adapter.send(upperPayload);

      const sentEmails = adapter.getSentEmails();
      expect(sentEmails[0]?.to).toBe('alice@example.com');
    });

    it('should trim whitespace from recipient email', async () => {
      const spacedPayload: NotificationPayload = {
        ...samplePayload,
        recipient: '  alice@example.com  ',
      };

      await adapter.send(spacedPayload);

      const sentEmails = adapter.getSentEmails();
      expect(sentEmails[0]?.to).toBe('alice@example.com');
    });

    it('should record the from address from config', async () => {
      await adapter.send(samplePayload);

      const sentEmails = adapter.getSentEmails();
      expect(sentEmails[0]?.from).toBe('noreply@taskflow.dev');
    });

    it('should include rendered HTML in sent emails', async () => {
      await adapter.send(samplePayload);

      const sentEmails = adapter.getSentEmails();
      expect(sentEmails[0]?.html).toContain('<!DOCTYPE html>');
      expect(sentEmails[0]?.html).toContain('Order Confirmed!');
    });

    it('should include rendered plain text in sent emails', async () => {
      await adapter.send(samplePayload);

      const sentEmails = adapter.getSentEmails();
      expect(sentEmails[0]?.text).toContain('Order Confirmed!');
      expect(sentEmails[0]?.text).toContain('Your order has been placed.');
    });

    it('should record notification type on sent emails', async () => {
      await adapter.send(samplePayload);

      const sentEmails = adapter.getSentEmails();
      expect(sentEmails[0]?.notificationType).toBe('order_confirmation');
    });

    it('should record composedAt timestamp on sent emails', async () => {
      const before = new Date();
      await adapter.send(samplePayload);
      const after = new Date();

      const sentEmails = adapter.getSentEmails();
      expect(sentEmails[0]?.composedAt.getTime()).toBeGreaterThanOrEqual(
        before.getTime(),
      );
      expect(sentEmails[0]?.composedAt.getTime()).toBeLessThanOrEqual(
        after.getTime(),
      );
    });

    it('should handle multiple sequential sends', async () => {
      await adapter.send(samplePayload);
      await adapter.send({
        ...samplePayload,
        recipient: 'bob@example.com',
        subject: 'Second Email',
      });

      const sentEmails = adapter.getSentEmails();
      expect(sentEmails).toHaveLength(2);
      expect(sentEmails[0]?.to).toBe('alice@example.com');
      expect(sentEmails[1]?.to).toBe('bob@example.com');
    });

    it('should propagate metadata from payload to email message', async () => {
      const payloadWithMeta: NotificationPayload = {
        ...samplePayload,
        metadata: { orderId: 'order-0001', trackingUrl: 'https://track.example.com' },
      };

      await adapter.send(payloadWithMeta);

      const sentEmails = adapter.getSentEmails();
      expect(sentEmails[0]?.metadata).toEqual({
        orderId: 'order-0001',
        trackingUrl: 'https://track.example.com',
      });
    });

    it('should not throw even when send encounters an error', async () => {
      const productionAdapter = new EmailAdapter({
        stubMode: false,
        maxRetries: 1,
      });

      // Should not throw — returns failure result instead
      const result = await productionAdapter.send(samplePayload);
      expect(result.success).toBe(false);
      expect(result.failureReason).toBeDefined();
    });
  });

  // -------------------------------------------------------------------------
  // Configuration
  // -------------------------------------------------------------------------

  describe('configuration', () => {
    it('should use default config when none provided', () => {
      const defaultAdapter = new EmailAdapter();
      const config = defaultAdapter.getConfig();

      expect(config.host).toBe('localhost');
      expect(config.port).toBe(587);
      expect(config.fromAddress).toBe('noreply@taskflow.dev');
      expect(config.stubMode).toBe(true);
    });

    it('should merge custom config with defaults', () => {
      const customAdapter = new EmailAdapter({
        host: 'smtp.example.com',
        fromAddress: 'app@example.com',
      });
      const config = customAdapter.getConfig();

      expect(config.host).toBe('smtp.example.com');
      expect(config.fromAddress).toBe('app@example.com');
      expect(config.port).toBe(587); // default preserved
    });

    it('should include companyName in default config', () => {
      const config = adapter.getConfig();
      expect(config.companyName).toBe('TaskFlow Pro');
    });

    it('should allow custom company name', () => {
      const customAdapter = new EmailAdapter({ companyName: 'My Store' });
      const config = customAdapter.getConfig();
      expect(config.companyName).toBe('My Store');
    });

    it('should include maxRetries in default config', () => {
      const config = adapter.getConfig();
      expect(config.maxRetries).toBe(3);
    });

    it('should return a defensive copy of config', () => {
      const config1 = adapter.getConfig();
      const config2 = adapter.getConfig();
      expect(config1).toEqual(config2);
      expect(config1).not.toBe(config2);
    });
  });

  // -------------------------------------------------------------------------
  // Channel Property
  // -------------------------------------------------------------------------

  describe('channel property', () => {
    it('should report email as its channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  // -------------------------------------------------------------------------
  // clearSentEmails
  // -------------------------------------------------------------------------

  describe('clearSentEmails', () => {
    it('should clear sent email records', async () => {
      await adapter.send(samplePayload);
      expect(adapter.getSentEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

  // -------------------------------------------------------------------------
  // Template Rendering
  // -------------------------------------------------------------------------

  describe('template rendering', () => {
    it('should render order_confirmation template with HTML and text', () => {
      const rendered = adapter.renderTemplate(samplePayload);

      expect(rendered.subject).toBe('Order Confirmation: order-0001');
      expect(rendered.html).toContain('<!DOCTYPE html>');
      expect(rendered.html).toContain('Order Confirmed!');
      expect(rendered.html).toContain('Your order has been placed.');
      expect(rendered.text).toContain('Order Confirmed!');
      expect(rendered.text).toContain('Your order has been placed.');
    });

    it('should render order_status_update template', () => {
      const statusPayload: NotificationPayload = {
        type: 'order_status_update',
        recipient: 'alice@example.com',
        subject: 'Order Update: order-0001',
        body: 'Your order status has changed from pending to shipped.',
        channel: 'email',
        priority: 'normal',
      };

      const rendered = adapter.renderTemplate(statusPayload);

      expect(rendered.html).toContain('Order Status Update');
      expect(rendered.html).toContain('pending to shipped');
      expect(rendered.text).toContain('Order Status Update');
    });

    it('should render high-priority status update with warning style', () => {
      const cancelledPayload: NotificationPayload = {
        type: 'order_status_update',
        recipient: 'alice@example.com',
        subject: 'Order Update: order-0001',
        body: 'Your order has been cancelled.',
        channel: 'email',
        priority: 'high',
      };

      const rendered = adapter.renderTemplate(cancelledPayload);

      // High priority renders with red/warning styling
      expect(rendered.html).toContain('#dc3545');
      expect(rendered.text).toContain('⚠️');
    });

    it('should render welcome template with getting started section', () => {
      const welcomePayload: NotificationPayload = {
        type: 'welcome',
        recipient: 'bob@example.com',
        subject: 'Welcome to TaskFlow Pro!',
        body: 'Hi Bob, welcome to TaskFlow Pro. Your account has been created.',
        channel: 'email',
        priority: 'normal',
      };

      const rendered = adapter.renderTemplate(welcomePayload);

      expect(rendered.html).toContain('Welcome!');
      expect(rendered.html).toContain('Getting Started');
      expect(rendered.html).toContain('Browse our product catalog');
      expect(rendered.text).toContain('Getting Started');
      expect(rendered.text).toContain('Browse our product catalog');
    });

    it('should render account_updated template with security notice', () => {
      const updatePayload: NotificationPayload = {
        type: 'account_updated',
        recipient: 'bob@example.com',
        subject: 'Account Updated',
        body: 'Your account has been updated. Changed fields: name, role.',
        channel: 'email',
        priority: 'low',
      };

      const rendered = adapter.renderTemplate(updatePayload);

      expect(rendered.html).toContain('Account Updated');
      expect(rendered.html).toContain('did not make these changes');
      expect(rendered.text).toContain('did not make these changes');
    });

    it('should include company name in templates', () => {
      const rendered = adapter.renderTemplate(samplePayload);

      expect(rendered.html).toContain('TaskFlow Pro');
      expect(rendered.text).toContain('TaskFlow Pro');
    });

    it('should use custom company name in templates', () => {
      const customAdapter = new EmailAdapter({ companyName: 'My Shop' });
      const rendered = customAdapter.renderTemplate(samplePayload);

      expect(rendered.html).toContain('My Shop');
      expect(rendered.text).toContain('My Shop');
    });

    it('should include automated message footer in all templates', () => {
      const types: NotificationPayload['type'][] = [
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_updated',
      ];

      for (const type of types) {
        const payload: NotificationPayload = {
          ...samplePayload,
          type,
        };
        const rendered = adapter.renderTemplate(payload);
        expect(rendered.html).toContain('automated message');
        expect(rendered.text).toContain('automated message');
      }
    });

    it('should escape HTML characters in template body', () => {
      const xssPayload: NotificationPayload = {
        ...samplePayload,
        body: 'Items: <script>alert("xss")</script> & "more"',
      };

      const rendered = adapter.renderTemplate(xssPayload);

      expect(rendered.html).not.toContain('<script>');
      expect(rendered.html).toContain('&lt;script&gt;');
      expect(rendered.html).toContain('&amp;');
    });
  });

  // -------------------------------------------------------------------------
  // Recipient Validation
  // -------------------------------------------------------------------------

  describe('recipient validation', () => {
    it('should accept valid email addresses', () => {
      expect(adapter.validateRecipient('alice@example.com')).toBe(true);
      expect(adapter.validateRecipient('user.name@example.co.uk')).toBe(true);
      expect(adapter.validateRecipient('user+tag@example.com')).toBe(true);
    });

    it('should reject invalid email addresses', () => {
      expect(adapter.validateRecipient('')).toBe(false);
      expect(adapter.validateRecipient('not-an-email')).toBe(false);
      expect(adapter.validateRecipient('@example.com')).toBe(false);
      expect(adapter.validateRecipient('user@')).toBe(false);
      expect(adapter.validateRecipient('user@.com')).toBe(false);
    });

    it('should accept emails with trimmed whitespace', () => {
      expect(adapter.validateRecipient('  alice@example.com  ')).toBe(true);
    });
  });
});

// ---------------------------------------------------------------------------
// Standalone utility function tests
// ---------------------------------------------------------------------------

describe('isValidEmail', () => {
  it('should accept standard email addresses', () => {
    expect(isValidEmail('user@example.com')).toBe(true);
    expect(isValidEmail('first.last@example.com')).toBe(true);
    expect(isValidEmail('user+tag@example.com')).toBe(true);
    expect(isValidEmail('user@sub.domain.example.com')).toBe(true);
  });

  it('should reject invalid formats', () => {
    expect(isValidEmail('')).toBe(false);
    expect(isValidEmail('plaintext')).toBe(false);
    expect(isValidEmail('@missing-local.com')).toBe(false);
    expect(isValidEmail('user@')).toBe(false);
    expect(isValidEmail('user@.com')).toBe(false);
    expect(isValidEmail('user@com')).toBe(false);
    expect(isValidEmail('user space@example.com')).toBe(false);
  });

  it('should reject null/undefined-like values', () => {
    expect(isValidEmail('' as string)).toBe(false);
    expect(isValidEmail(null as unknown as string)).toBe(false);
    expect(isValidEmail(undefined as unknown as string)).toBe(false);
  });

  it('should reject overly long addresses', () => {
    const longLocal = 'a'.repeat(250);
    expect(isValidEmail(`${longLocal}@example.com`)).toBe(false);
  });
});

describe('resolveRecipient', () => {
  it('should normalise valid emails to lowercase', () => {
    expect(resolveRecipient('Alice@EXAMPLE.COM')).toBe('alice@example.com');
  });

  it('should trim whitespace', () => {
    expect(resolveRecipient('  bob@example.com  ')).toBe('bob@example.com');
  });

  it('should return null for invalid emails', () => {
    expect(resolveRecipient('not-valid')).toBeNull();
    expect(resolveRecipient('')).toBeNull();
  });

  it('should return null for empty/null input', () => {
    expect(resolveRecipient(null as unknown as string)).toBeNull();
    expect(resolveRecipient(undefined as unknown as string)).toBeNull();
  });
});

describe('renderEmailTemplate', () => {
  it('should render all notification types without errors', () => {
    const types: NotificationPayload['type'][] = [
      'order_confirmation',
      'order_status_update',
      'welcome',
      'account_updated',
    ];

    for (const type of types) {
      const payload: NotificationPayload = {
        type,
        recipient: 'test@example.com',
        subject: `Test ${type}`,
        body: `Body for ${type}`,
        channel: 'email',
        priority: 'normal',
      };

      const rendered = renderEmailTemplate(payload, 'TestCo');

      expect(rendered.subject).toBe(`Test ${type}`);
      expect(rendered.html).toContain('<!DOCTYPE html>');
      expect(rendered.html).toContain('TestCo');
      expect(rendered.text).toContain('TestCo');
      expect(rendered.text.length).toBeGreaterThan(0);
    }
  });
});

