/**
 * Simple delay utility for retry backoff.
 * Uses a busy-wait approach to avoid reliance on setTimeout
 * in environments where it may not be available.
 */
private delay(ms: number): Promise<void> {
  const start = Date.now();
  return new Promise<void>((resolve) => {
    const check = (): void => {
      if (Date.now() - start >= ms) {
        resolve();
      } else {
        // Use queueMicrotask as a portable alternative to setTimeout
        queueMicrotask(check);
      }
    };
    check();
  });
}

