describe('resolveRecipient', () => {
  it('should normalise valid emails to lowercase', () => {
    const result = resolveRecipient('Alice@EXAMPLE.COM');
    expect(result).not.toBeNull();
    expect(result!.address).toBe('alice@example.com');
    expect(result!.isValidEmail).toBe(true);
  });

  it('should trim whitespace', () => {
    const result = resolveRecipient('  bob@example.com  ');
    expect(result).not.toBeNull();
    expect(result!.address).toBe('bob@example.com');
  });

  it('should resolve non-email identifiers with isValidEmail=false', () => {
    const result = resolveRecipient('user-1');
    expect(result).not.toBeNull();
    expect(result!.address).toBe('user-1');
    expect(result!.isValidEmail).toBe(false);
  });

  it('should return null for empty string', () => {
    expect(resolveRecipient('')).toBeNull();
  });

  it('should return null for whitespace-only string', () => {
    expect(resolveRecipient('   ')).toBeNull();
  });

  it('should return null for null/undefined input', () => {
    expect(resolveRecipient(null as unknown as string)).toBeNull();
    expect(resolveRecipient(undefined as unknown as string)).toBeNull();
  });
});

